// DuelGrid App.jsx - React-based tactical game with 8 characters per team, turn-based gameplay, and strategy roles

import React, { useState } from 'react';
import './App.css';

const gridSize = 8;

const baseCharacters = [
  { name: 'Knight', hp: 100, atk: 30, sprite: '/sprites/knight.png', move: 2 },
  { name: 'Archer', hp: 80, atk: 25, sprite: '/sprites/archer.png', move: 3 },
  { name: 'Mage', hp: 70, atk: 40, sprite: '/sprites/mage.png', move: 2 },
  { name: 'Healer', hp: 90, atk: 10, sprite: '/sprites/healer.png', move: 2 },
  { name: 'Warrior', hp: 110, atk: 35, sprite: '/sprites/warrior.png', move: 1 },
  { name: 'Rogue', hp: 75, atk: 30, sprite: '/sprites/rogue.png', move: 4 },
  { name: 'Summoner', hp: 65, atk: 45, sprite: '/sprites/summoner.png', move: 2 },
  { name: 'Paladin', hp: 95, atk: 20, sprite: '/sprites/paladin.png', move: 1 },
];

let idCounter = 1;
const generateTeam = (team, row) => baseCharacters.map((c, i) => ({
  ...c,
  id: idCounter++,
  x: i,
  y: row,
  team,
}));

const initialCharacters = [
  ...generateTeam('A', 0),
  ...generateTeam('B', gridSize - 1)
];

function App() {
  const [characters, setCharacters] = useState(initialCharacters);
  const [selectedId, setSelectedId] = useState(null);
  const [turn, setTurn] = useState('A');
  const [movesLeft, setMovesLeft] = useState(0);
  const [attackUsed, setAttackUsed] = useState(false);

  const selectedChar = characters.find(c => c.id === selectedId);

  const moveCharacter = (id, dx, dy) => {
    if (movesLeft <= 0) return;
    setCharacters(prev =>
      prev.map(c => {
        if (c.id === id && c.team === turn) {
          const newX = Math.max(0, Math.min(gridSize - 1, c.x + dx));
          const newY = Math.max(0, Math.min(gridSize - 1, c.y + dy));
          if (!characters.find(other => other.x === newX && other.y === newY && other.hp > 0)) {
            setMovesLeft(movesLeft - 1);
            return { ...c, x: newX, y: newY };
          }
        }
        return c;
      })
    );
  };

  const attack = attackerId => {
    if (attackUsed) return;
    const attacker = characters.find(c => c.id === attackerId);
    const targets = characters.filter(
      c => c.team !== attacker.team && Math.abs(c.x - attacker.x) + Math.abs(c.y - attacker.y) === 1 && c.hp > 0
    );
    if (targets.length > 0) {
      const target = targets[0];
      setCharacters(prev =>
        prev.map(c =>
          c.id === target.id ? { ...c, hp: Math.max(0, c.hp - attacker.atk) } : c
        )
      );
      setAttackUsed(true);
    }
  };

  const endTurn = () => {
    setSelectedId(null);
    setTurn(prev => (prev === 'A' ? 'B' : 'A'));
    setMovesLeft(0);
    setAttackUsed(false);
  };

  const selectCharacter = (char) => {
    if (char.team === turn && char.hp > 0) {
      setSelectedId(char.id);
      setMovesLeft(char.move);
      setAttackUsed(false);
    }
  };

  return (
    <div className="App">
      <h1>DuelGrid</h1>
      <h2>Turn: Team {turn}</h2>
      <div className="grid">
        {Array.from({ length: gridSize }).map((_, y) => (
          <div key={y} className="row">
            {Array.from({ length: gridSize }).map((_, x) => {
              const char = characters.find(c => c.x === x && c.y === y && c.hp > 0);
              return (
                <div
                  key={x}
                  className={`tile ${char ? 'occupied' : ''}`}
                  onClick={() => char && selectCharacter(char)}
                >
                  {char && (
                    <div className="character">
                      <img src={char.sprite} alt={char.name} className="sprite" />
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        ))}
      </div>
      <div className="controls">
        {selectedChar && selectedChar.team === turn && selectedChar.hp > 0 && (
          <>
            <div className="stats-panel">
              <div>{selectedChar.name}</div>
              <div>HP: {selectedChar.hp}</div>
              <div>ATK: {selectedChar.atk}</div>
              <div>Moves Left: {movesLeft}</div>
            </div>
            <div className="buttons">
              <button onClick={() => moveCharacter(selectedId, -1, 0)}>←</button>
              <button onClick={() => moveCharacter(selectedId, 1, 0)}>→</button>
              <button onClick={() => moveCharacter(selectedId, 0, -1)}>↑</button>
              <button onClick={() => moveCharacter(selectedId, 0, 1)}>↓</button>
              <button onClick={() => attack(selectedId)} disabled={attackUsed}>Attack</button>
              <button onClick={endTurn}>End Turn</button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

export default App;
